import{_ as d,o as a,c as r,a2 as e}from"./chunks/framework.ZhLefgN8.js";const c=JSON.parse('{"title":"个股财务分析","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"market-data/financials.md","filePath":"zh-CN/market-data/financials.md"}'),l={name:"market-data/financials.md"};function i(o,t,h,n,b,s){return a(),r("div",null,[...t[0]||(t[0]=[e('<h1 id="个股财务分析" tabindex="-1">个股财务分析 <a class="header-anchor" href="#个股财务分析" aria-label="Permalink to &quot;个股财务分析&quot;">​</a></h1><p>财务分析页面提供上市公司三大财务报表的深度解读，涵盖利润表、资产负债表、现金流量表及股息数据，并支持与同行业公司对比。帮助投资者快速了解公司盈利能力、资产结构和现金状况。</p><p>入口：长桥 App - 个股详情页 - 财务</p><h2 id="财报速览" tabindex="-1">财报速览 <a class="header-anchor" href="#财报速览" aria-label="Permalink to &quot;财报速览&quot;">​</a></h2><p>页面顶部提供最新一期财报的核心数据摘要，包含公布值、同比变化及与市场预测值的对比情况。</p><table tabindex="0"><thead><tr><th>指标</th><th>说明</th></tr></thead><tbody><tr><td>营业收入</td><td>当期总收入，显示公布值与预测值对比</td></tr><tr><td>息税前利润</td><td>扣除利息和税前的利润（EBIT）</td></tr><tr><td>每股收益</td><td>EPS，显示实际值与分析师预期值对比</td></tr></tbody></table><ul><li>可通过图表直观对比「公布值」与「预测值」的走势</li><li>点击「更多」查看完整财报内容</li></ul><blockquote><p><strong>一图读懂财报</strong>：页面顶部提供当季财报的图文摘要，快速掌握公司财务状况的整体概况。</p></blockquote><h2 id="利润表" tabindex="-1">利润表 <a class="header-anchor" href="#利润表" aria-label="Permalink to &quot;利润表&quot;">​</a></h2><p>展示公司盈利情况，可按单季报或年报查看，支持历史多期数据横向对比。</p><table tabindex="0"><thead><tr><th>指标</th><th>说明</th></tr></thead><tbody><tr><td>每股收益（EPS）</td><td>每股对应的净利润</td></tr><tr><td>ROE</td><td>净资产收益率，衡量股东权益回报</td></tr><tr><td>营业收入</td><td>当期实现的总营收</td></tr><tr><td>净利润</td><td>扣除所有费用后的最终利润</td></tr><tr><td>营业利润</td><td>扣除营业成本和费用后的利润</td></tr><tr><td>毛利率</td><td>毛利润占营业收入的比例</td></tr><tr><td>净利率</td><td>净利润占营业收入的比例</td></tr><tr><td>利润含金量</td><td>经营现金流与净利润的匹配程度</td></tr></tbody></table><ul><li>列表展示近 5 个季度的历史数据，包含环比变动和股价走势</li><li>点击「更多」可查看更多历史期数据</li></ul><h2 id="资产负债表" tabindex="-1">资产负债表 <a class="header-anchor" href="#资产负债表" aria-label="Permalink to &quot;资产负债表&quot;">​</a></h2><p>展示公司在特定时点的资产、负债和股东权益状况，帮助判断公司财务健康程度。</p><table tabindex="0"><thead><tr><th>指标</th><th>说明</th></tr></thead><tbody><tr><td>资产与负债</td><td>总资产与总负债的规模及变化趋势</td></tr><tr><td>权益乘数</td><td>总资产与股东权益之比，反映杠杆程度</td></tr><tr><td>每股净资产</td><td>每股对应的账面净资产价值</td></tr><tr><td>资产周转率</td><td>资产创造收入的效率</td></tr><tr><td>现金及短投</td><td>现金及短期投资金额</td></tr><tr><td>存货与应收</td><td>存货和应收账款情况</td></tr><tr><td>长期投资</td><td>长期股权及其他投资规模</td></tr><tr><td>净债务</td><td>有息负债减去现金及现金等价物</td></tr></tbody></table><ul><li>支持查看当前公司在同行业中的资产负债排名（如：43/99）</li><li>图表展示总资产与总负债的历史走势，以及与营收、净利润的关联分析</li></ul><h2 id="现金流量表" tabindex="-1">现金流量表 <a class="header-anchor" href="#现金流量表" aria-label="Permalink to &quot;现金流量表&quot;">​</a></h2><p>展示公司实际现金的流入与流出情况，是判断公司造血能力的重要依据。</p><table tabindex="0"><thead><tr><th>指标</th><th>说明</th></tr></thead><tbody><tr><td>经营现金流</td><td>主营业务带来的现金净额</td></tr><tr><td>投资现金流</td><td>投资活动产生的现金净额</td></tr><tr><td>融资现金流</td><td>融资活动（借款、发债、股权融资等）产生的现金净额</td></tr><tr><td>自由现金流</td><td>经营现金流减去资本支出后的可自由支配现金</td></tr><tr><td>现金流充裕率</td><td>经营现金流覆盖负债的能力</td></tr><tr><td>举债与偿债</td><td>新增借款与还款情况</td></tr><tr><td>资本支出</td><td>购置固定资产、设备等长期资产的支出</td></tr></tbody></table><ul><li>列表展示近 5 个季度历史数据，含环比变动</li><li>点击「了解更多经营现金流相关知识」可查看指标说明</li></ul><h2 id="股息相关" tabindex="-1">股息相关 <a class="header-anchor" href="#股息相关" aria-label="Permalink to &quot;股息相关&quot;">​</a></h2><p>展示公司历史派息记录及股息相关指标，适用于关注现金回报的投资者。</p><table tabindex="0"><thead><tr><th>指标</th><th>说明</th></tr></thead><tbody><tr><td>股息及股息率</td><td>每股股息金额及其相对股价的收益率</td></tr><tr><td>股息/净利润</td><td>派息比例，衡量公司分红意愿</td></tr><tr><td>股息/现金流</td><td>股息与经营现金流的比值</td></tr><tr><td>股息增长率</td><td>历史股息的增长趋势</td></tr></tbody></table><blockquote><p>部分公司暂不派息，此模块将显示「暂无数据」。</p></blockquote><h2 id="同行业公司对比" tabindex="-1">同行业公司对比 <a class="header-anchor" href="#同行业公司对比" aria-label="Permalink to &quot;同行业公司对比&quot;">​</a></h2><p>各财务模块均支持与同行业公司横向对比：</p><ul><li>查看当前公司在行业中的指标排名位置（如：排名 43/99）</li><li>通过「相关」入口跳转至同类公司的财务数据对比页</li><li>图表同步展示股价走势与财务指标的相关性</li></ul><h2 id="数据筛选与切换" tabindex="-1">数据筛选与切换 <a class="header-anchor" href="#数据筛选与切换" aria-label="Permalink to &quot;数据筛选与切换&quot;">​</a></h2><ul><li><strong>报告期切换</strong>：支持「单季报」和「年报」两种视图，方便对比季度与全年表现</li><li><strong>币种说明</strong>：数据默认以公司报告货币展示（如 USD），页面顶部标注当前币种</li><li><strong>历史数据</strong>：点击各模块的「更多」按钮，可查看更多历史期数据</li></ul><blockquote><p>以上行情、资讯及其他数据来自第三方数据源，仅供参考，不构成投资建议。</p></blockquote>',30)])])}const p=d(l,[["render",i]]);export{c as __pageData,p as default};
